Here's the full setup:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalTextAlignment="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { { "Item", CurrentItem } });

        // Clear selection so the same item can be re-selected later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // stops the spinner
        }
    }
}
```

### Key binding notes

| Property | Purpose |
|---|---|
| `SelectedItem` → `CurrentItem` (TwoWay) | Tracks which item the user tapped |
| `SelectionChangedCommand` → `ItemSelectedCommand` | Fires navigation; resets `CurrentItem` to `null` afterward so the same row can be tapped again |
| `RefreshView.IsRefreshing` → `IsRefreshing` (TwoWay) | Controls the spinner — set to `false` when the API call finishes |
| `RefreshView.Command` → `RefreshCommand` | Triggers data reload |
| `ItemsSource` → `ObservableCollection<Item>` | Use `ObservableCollection`, not `List`, so add/remove updates the UI automatically |

**Important:** Always update the collection on the UI thread (`MainThread.BeginInvokeOnMainThread`) and always set `x:DataType` on `DataTemplate` for compiled bindings.
